56	  padding: "var(--space-md)",
57	  borderRadius: "var(--radius-md)",
58	  border: "1px solid var(--color-border)",
59	  background: "var(--color-bg-surface)",
60	  minHeight: 112,
61	};
62	
63	const labelStyle: React.CSSProperties = {
64	  fontSize: "0.74rem",
65	  fontWeight: 700,
66	  letterSpacing: "0.08em",
67	  textTransform: "uppercase",
68	  color: "var(--color-text-muted)",
69	  marginBottom: "var(--space-sm)",
70	};
71	
